24	template<typename T>
25	struct FtWeight {
26	
27	public:
28	    std::string         name_;
29	    std::vector<size_t> shape_;
30	    size_t              size_ = 0;
31	    T*                  ptr_  = nullptr;
32	
33	    FtWeight() {}
34	    FtWeight(const std::string name, const std::vector<size_t> shape, T* ptr): name_(name), shape_(shape), ptr_(ptr)
35	    {
36	        size_ = 1;
37	        for (uint i = 0; i < shape_.size(); i++) {
