28	template<typename T>
29	struct ParallelGptWeight {
30	
31	    ParallelGptWeight() = default;
32	    ParallelGptWeight(const int                                  hidden_units,
33	                      const int                                  inter_size,
34	                      const int                                  vocab_size,
35	                      const int                                  num_layer,
36	                      const int                                  max_seq_len,
37	                      const int                                  tensor_para_size,
38	                      const int                                  tensor_para_rank,
39	                      const int                                  layer_para_size,
40	                      const int                                  layer_para_rank,
41	                      const int                                  int8_mode            = 0,
42	                      PromptLearningType                         prompt_learning_type = PromptLearningType::no_prompt,
43	                      std::map<std::string, std::pair<int, int>> prompt_learning_pair = {},
44	                      gptVariantParams                           gpt_variant_params   = {});
45	    ~ParallelGptWeight();
46	    ParallelGptWeight(const ParallelGptWeight& other);
47	    ParallelGptWeight& operator=(const ParallelGptWeight& other);
48	    void               loadModel(std::string dir_path);
49	    void               resizeLayer(const int num_layer, const int int8_mode = 0);
50	#ifdef SPARSITY_ENABLED
51	    void compress_weights(cublasMMWrapper& cublas_wrapper);
52	#endif
53	
54	    std::vector<ParallelGptDecoderLayerWeight<T>*> decoder_layer_weights;
55	    const T*                                       position_encoding_table     = nullptr;
56	    const T*                                       pre_decoder_embedding_table = nullptr;
57	    LayerNormWeight<T>                             pre_decoder_layernorm;
58	    LayerNormWeight<T>                             post_decoder_layernorm;
59	    DenseWeight<T>                                 post_decoder_embedding;
60	
61	    /*
62	       prompt_learning_pair = vectors of [weight ptr, prompt length] pair
63	       prompt_length is stored here for compatible prompt learning table
64	       prefix_prompt weights store as shape [num_layers, 2, num_heads, perfix_seq_len, size_per_head]
65	       p/prompt tuning weights store as shape [prompt_len, hidden_units]
66	       idx is the task_name_id of the prompt tables
67	    */
68	    std::vector<std::pair<const T*, int>> prompt_learning_table = {};
69	    inline size_t                         getMaxSeqLen() const
70	    {
71	        return max_seq_len_;
72	    }
73	    inline void setMaxSeqLen(size_t max_seq_len)
74	    {
75	        max_seq_len_ = max_seq_len;
76	    }
77	
78	private:
79	    void setWeightPtr();
80	    void mallocWeights();
81	    bool isValidLayerParallelId(int l);
82	
83	    size_t hidden_units_;
84	    size_t inter_size_;
85	    size_t vocab_size_;
86	    size_t num_layer_;
87	    size_t max_seq_len_;
88	    size_t tensor_para_size_;
89	    size_t tensor_para_rank_;
90	    size_t layer_para_size_;
91	    size_t layer_para_rank_;
92	    size_t int8_mode_    = 0;
93	    bool   shared_embed_ = false;
94	
95	    // gpt variants: e.g. meta opt
96	    gptVariantParams gpt_variant_params_;
97	
98	    // prompt learning pair (task_name, (task_name_id, prompt_len))
99	    PromptLearningType                         prompt_learning_type_;
100	    std::map<std::string, std::pair<int, int>> prompt_learning_pair_;
101	    bool                                       malloc_load_prompt_weights_ = false;
102	    // each prompt token's weight size
103	    size_t prompt_token_weight_size_ = 0;
104	
105	    bool is_maintain_buffer = false;
106	
107	    // The number of base weights of the GPT model: According to the variant params,
108	    // positional encoding or pre decoder layernorm can be nullptr.
109	    //  - 1 for the positional encoding. (optional)
110	    //  - 1 for the pre word embedding tables.
111	    //  - 2 for the pre decoder layernorm. (optional)
112	    //  - 2 for the post decoder layernorm. (optional)
113	    //  - 2 for the post word embedding tables.
114	    size_t num_base_weights = 7;
115	    // weight pointers of length num_base_weights.
116	    std::vector<T*> weights_ptr = std::vector<T*>(num_base_weights);
117	};
