21	template<typename T>
22	BertLayerWeight<T>::BertLayerWeight(const size_t hidden_units,
23	                                    const size_t inter_size,
24	                                    const size_t tensor_para_size,
25	                                    const size_t tensor_para_rank):
26	    hidden_units_(hidden_units),
27	    inter_size_(inter_size),
28	    tensor_para_size_(tensor_para_size),
29	    tensor_para_rank_(tensor_para_rank)
30	{
31	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
32	    std::string name;
33	
34	    name = "attention.self.query.weight." + std::to_string(tensor_para_rank_) + ".bin";
35	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_, hidden_units_ / tensor_para_size_}, nullptr)});
36	    name = "attention.self.query.bias." + std::to_string(tensor_para_rank_) + ".bin";
37	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_ / tensor_para_size_}, nullptr)});
38	    name = "attention.self.key.weight." + std::to_string(tensor_para_rank_) + ".bin";
39	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_, hidden_units_ / tensor_para_size_}, nullptr)});
40	    name = "attention.self.key.bias." + std::to_string(tensor_para_rank_) + ".bin";
41	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_ / tensor_para_size_}, nullptr)});
42	    name = "attention.self.value.weight." + std::to_string(tensor_para_rank_) + ".bin";
43	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_, hidden_units_ / tensor_para_size_}, nullptr)});
44	    name = "attention.self.value.bias." + std::to_string(tensor_para_rank_) + ".bin";
45	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_ / tensor_para_size_}, nullptr)});
46	    name = "attention.output.dense.weight." + std::to_string(tensor_para_rank_) + ".bin";
47	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_, hidden_units_ / tensor_para_size_}, nullptr)});
48	    name = "attention.output.dense.bias.bin";
49	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
50	    name = "attention.output.LayerNorm.weight.bin";
51	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
52	    name = "attention.output.LayerNorm.bias.bin";
53	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
54	    name = "intermediate.dense.weight." + std::to_string(tensor_para_rank_) + ".bin";
55	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_, inter_size_ / tensor_para_size_}, nullptr)});
56	    name = "intermediate.dense.bias." + std::to_string(tensor_para_rank_) + ".bin";
57	    weights_ptr.insert({name, FtWeight<T>(name, {inter_size_ / tensor_para_size_}, nullptr)});
58	    name = "output.dense.weight." + std::to_string(tensor_para_rank_) + ".bin";
59	    weights_ptr.insert({name, FtWeight<T>(name, {inter_size_ / tensor_para_size_, hidden_units_}, nullptr)});
60	    name = "output.dense.bias.bin";
61	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
62	    name = "output.LayerNorm.weight.bin";
63	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
64	    name = "output.LayerNorm.bias.bin";
65	    weights_ptr.insert({name, FtWeight<T>(name, {hidden_units_}, nullptr)});
66	
67	    for (auto it = weights_ptr.begin(); it != weights_ptr.end(); ++it) {
68	        deviceMalloc(&it->second.ptr_, it->second.size_);
69	    }
70	    setWeightPtr();
71	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
72	}
73	
74	template<typename T>
75	BertLayerWeight<T>::~BertLayerWeight()
76	{
77	    if (is_maintain_buffer == true) {
78	        for (auto it = weights_ptr.begin(); it != weights_ptr.end(); ++it) {
79	            deviceFree(it->second.ptr_);
80	        }
81	        weights_ptr.clear();
82	
83	        attention_weights.query_weight.kernel            = nullptr;
84	        attention_weights.query_weight.bias              = nullptr;
85	        attention_weights.key_weight.kernel              = nullptr;
86	        attention_weights.key_weight.bias                = nullptr;
87	        attention_weights.value_weight.kernel            = nullptr;
88	        attention_weights.value_weight.bias              = nullptr;
89	        attention_weights.attention_output_weight.kernel = nullptr;
90	        attention_weights.attention_output_weight.bias   = nullptr;
91	        attn_layernorm_weights.gamma                     = nullptr;
92	        attn_layernorm_weights.beta                      = nullptr;
93	        ffn_weights.intermediate_weight.kernel           = nullptr;
94	        ffn_weights.intermediate_weight.bias             = nullptr;
95	        ffn_weights.output_weight.kernel                 = nullptr;
96	        ffn_weights.output_weight.bias                   = nullptr;
97	        ffn_layernorm_weights.gamma                      = nullptr;
98	        ffn_layernorm_weights.beta                       = nullptr;
99	        is_maintain_buffer                               = false;
100	    }
101	    if (is_maintain_sp_buffer == true) {
102	        for (int i = 0; i < 6; i++) {
103	            deviceFree(sp_weights_ptr[i]);
104	        }
105	        attention_weights.query_weight.sp_kernel            = nullptr;
106	        attention_weights.key_weight.sp_kernel              = nullptr;
107	        attention_weights.value_weight.sp_kernel            = nullptr;
108	        attention_weights.attention_output_weight.sp_kernel = nullptr;
109	        ffn_weights.intermediate_weight.sp_kernel           = nullptr;
110	        ffn_weights.output_weight.sp_kernel                 = nullptr;
111	        is_maintain_sp_buffer                               = false;
112	    }
113	}
114	
115	template<typename T>
116	BertLayerWeight<T>::BertLayerWeight(const BertLayerWeight& other):
117	    BertLayerWeight(other.hidden_units_, other.inter_size_, other.tensor_para_size_, other.tensor_para_rank_)
118	{
119	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
120	    for (auto it = other.weights_ptr.begin(); it != other.weights_ptr.end(); ++it) {
121	        cudaD2Dcpy(weights_ptr.at(it->first).ptr_, it->second.ptr_, it->second.size_);
122	    }
123	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
124	}
125	
126	template<typename T>
127	BertLayerWeight<T>& BertLayerWeight<T>::operator=(const BertLayerWeight& other)
128	{
129	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
130	    hidden_units_     = other.hidden_units_;
131	    inter_size_       = other.inter_size_;
132	    tensor_para_size_ = other.tensor_para_size_;
133	    tensor_para_rank_ = other.tensor_para_rank_;
134	
135	    for (auto it = other.weights_ptr.begin(); it != other.weights_ptr.end(); ++it) {
136	        weights_ptr.insert({it->first, it->second});
137	        weights_ptr.at(it->first).ptr_ = nullptr;
138	        deviceMalloc(&weights_ptr.at(it->first).ptr_, it->second.size_);
139	        cudaD2Dcpy(weights_ptr.at(it->first).ptr_, it->second.ptr_, it->second.size_);
140	    }
141	    setWeightPtr();
142	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
143	
144	    return *this;
145	}
146	
147	#ifdef SPARSITY_ENABLED
148	template<typename T>
149	void BertLayerWeight<T>::compress_weights(cublasMMWrapper& cublas_wrapper, int hidden_dim)
150	{
151	    int inter_size = hidden_dim * 4;
152	    deviceMalloc(&sp_weights_ptr[0], hidden_dim * hidden_dim);
153	    deviceMalloc(&sp_weights_ptr[1], hidden_dim * hidden_dim);
154	    deviceMalloc(&sp_weights_ptr[2], hidden_dim * hidden_dim);
155	    deviceMalloc(&sp_weights_ptr[3], hidden_dim * hidden_dim);
156	    deviceMalloc(&sp_weights_ptr[4], hidden_dim * inter_size);
157	    deviceMalloc(&sp_weights_ptr[5], inter_size * hidden_dim);
158	    cublas_wrapper.compressMatrix(attention_weights.query_weight.kernel, sp_weights_ptr[0], hidden_dim, hidden_dim);
159	    cublas_wrapper.compressMatrix(attention_weights.key_weight.kernel, sp_weights_ptr[1], hidden_dim, hidden_dim);
160	    cublas_wrapper.compressMatrix(attention_weights.value_weight.kernel, sp_weights_ptr[2], hidden_dim, hidden_dim);
161	    cublas_wrapper.compressMatrix(
162	        attention_weights.attention_output_weight.kernel, sp_weights_ptr[3], hidden_dim, hidden_dim);
163	    cublas_wrapper.compressMatrix(ffn_weights.intermediate_weight.kernel, sp_weights_ptr[4], inter_size, hidden_dim);
164	    cublas_wrapper.compressMatrix(ffn_weights.output_weight.kernel, sp_weights_ptr[5], hidden_dim, inter_size);
165	    attention_weights.query_weight.sp_kernel            = sp_weights_ptr[0];
166	    attention_weights.key_weight.sp_kernel              = sp_weights_ptr[1];
167	    attention_weights.value_weight.sp_kernel            = sp_weights_ptr[2];
168	    attention_weights.attention_output_weight.sp_kernel = sp_weights_ptr[3];
169	    ffn_weights.intermediate_weight.sp_kernel           = sp_weights_ptr[4];
170	    ffn_weights.output_weight.sp_kernel                 = sp_weights_ptr[5];
171	    is_maintain_sp_buffer                               = true;
172	}
173	#endif
174	
175	template<typename T>
176	void BertLayerWeight<T>::loadModel(std::string dir_path, FtCudaDataType model_file_type)
177	{
178	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
179	    for (auto it = weights_ptr.begin(); it != weights_ptr.end(); ++it) {
